// ==============================================================
// WF2 — Ler (monday)
// Recebe o resultado de getByColumnValue, parseia as colunas
// e devolve no shape esperado pelo frontend.
// ==============================================================

// Colunas do board HISTÓRICO
const COL_UUID         = 'text_mm2xjend';
const COL_PROTOCOLO    = 'text_mm2xsvg6';
const COL_CONTRATO     = 'text_mm2x1ktb';
const COL_DATA_INICIO  = 'date_mm2xtp93';
const COL_DATA_FIM     = 'date_mm2xrr5q';
const COL_EXPIRA_EM    = 'date_mm2xrvt4';
const COL_CRIADO_EM    = 'date_mm2x115h';
const COL_CONCLUIDO    = 'date_mm2xh1vm';
const COL_EDITADO_EM   = 'date_mm2x62fq';
const COL_STATUS       = 'color_mm2xkqpc';
const COL_EDITADO      = 'boolean_mm2x1aa4';
const COL_DIAS_EXTRAS  = 'long_text_mm2x73w6';
const COL_DIAS_DESATIV = 'long_text_mm2xm820';
const COL_RESPOSTAS    = 'long_text_mm2xtcpw';
const COL_TRABALHA_SABADO = 'color_mm34yyet';
const COL_SABADOS_EXTRAS  = 'text_mm3bfn6h';

const all = $input.all();
const uuid = $('Webhook').first().json.query?.uuid;

// Quando getByColumnValue não acha nada, ou retorna [] ou um item-vazio
function firstRealItem() {
  for (const it of all) {
    const j = it.json;
    if (!j) continue;
    if (j.id && (j.column_values || j.name)) return j;
  }
  return null;
}

const item = firstRealItem();
if (!item) {
  return [{
    json: {
      _statusCode: 404,
      erro: 'nao_encontrado',
      mensagem: 'Link inválido ou expirado.'
    }
  }];
}

const columnValues = item.column_values ?? [];
const getCol = (id) => columnValues.find(c => c.id === id) || null;
const text = (id) => getCol(id)?.text ?? null;
const rawValue = (id) => getCol(id)?.value ?? null;

function parseDate(id) {
  // monday Date returns text 'YYYY-MM-DD' or 'YYYY-MM-DD HH:mm:ss'
  const t = text(id);
  if (!t) return null;
  return t;
}

function parseStatusLabel(id) {
  return text(id);
}

function parseCheckbox(id) {
  const v = rawValue(id);
  if (!v) return false;
  try {
    const parsed = typeof v === 'string' ? JSON.parse(v) : v;
    return parsed?.checked === true || parsed?.checked === 'true';
  } catch { return false; }
}

function parseLongTextJson(id, fallback) {
  const t = text(id);
  if (!t) return fallback;
  try { return JSON.parse(t); } catch { return fallback; }
}

const dataInicio = parseDate(COL_DATA_INICIO);
const dataFim    = parseDate(COL_DATA_FIM);
const statusLabel = parseStatusLabel(COL_STATUS);
const statusMap = {
  'Aguardando': 'aguardando',
  'Concluído':  'concluido',
  'Concluido':  'concluido',
  'Expirado':   'expirado'
};
let status = statusMap[statusLabel] || 'aguardando';

const expiraEm = parseDate(COL_EXPIRA_EM);
const agora = new Date();
if (status === 'aguardando' && expiraEm) {
  if (agora > new Date(expiraEm + 'T23:59:59Z')) status = 'expirado';
}

// Trabalha sábado (do board origem, label SIM/NÃO)
const trabalhaSabadoLabel = parseStatusLabel(COL_TRABALHA_SABADO);
const trabalhaSabado = !!trabalhaSabadoLabel && /sim/i.test(trabalhaSabadoLabel);

// Sábados extras (text livre): aceita lista separada por vírgula, ponto-e-vírgula ou quebra de linha
const sabadosExtrasRaw = text(COL_SABADOS_EXTRAS);
const sabadosExtras = sabadosExtrasRaw
  ? sabadosExtrasRaw
      .split(/[,;\n]/)
      .map(s => s.trim())
      .filter(s => /^\d{4}-\d{2}-\d{2}$/.test(s))
  : [];

// Lista de dias inclusivos (período base). Pula domingos sempre; pula
// sábados quando intermitente NÃO trabalha aos sábados (sábado extra
// entra via coluna própria, não na lista padrão).
const dias = [];
if (dataInicio && dataFim) {
  const cur = new Date(dataInicio + 'T00:00:00Z');
  const fim = new Date(dataFim + 'T00:00:00Z');
  while (cur <= fim) {
    const dow = cur.getUTCDay();
    const pular = dow === 0 || (!trabalhaSabado && dow === 6);
    if (!pular) dias.push(cur.toISOString().slice(0, 10));
    cur.setUTCDate(cur.getUTCDate() + 1);
  }
}

const respostas      = parseLongTextJson(COL_RESPOSTAS, []);
const diasExtras     = parseLongTextJson(COL_DIAS_EXTRAS, []);
const diasDesativ    = parseLongTextJson(COL_DIAS_DESATIV, []);

return [{
  json: {
    _statusCode: 200,
    uuid: text(COL_UUID) || uuid,
    status,
    nome: item.name,
    contrato: text(COL_CONTRATO),
    data_inicio: dataInicio,
    data_fim: dataFim,
    dias,
    expira_em: expiraEm,
    concluido_em: parseDate(COL_CONCLUIDO),
    protocolo: text(COL_PROTOCOLO),
    editado: parseCheckbox(COL_EDITADO),
    editado_em: parseDate(COL_EDITADO_EM),
    respostas,
    dias_extras: diasExtras,
    dias_desativados: diasDesativ,
    trabalha_sabado: trabalhaSabado,
    sabados_extras: sabadosExtras
  }
}];
